 1	import { type FC, useCallback } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	import { ItemIsOwnedAlert } from 'src/modules/Providers/modals/components/ItemIsOwnedAlert';
 4	import { getResourceUrl } from 'src/modules/Providers/utils/helpers/getResourceUrl';
 5	import { PlanStatuses } from 'src/plans/details/components/PlanStatus/utils/types';
 6	import { getPlanStatus } from 'src/plans/details/components/PlanStatus/utils/utils';
 7	import { ForkliftTrans, useForkliftTranslation } from 'src/utils/i18n';
 8	
 9	import ModalForm from '@components/ModalForm/ModalForm';
10	import { PlanModel, type V1beta1Plan } from '@kubev2v/types';
11	import { getGroupVersionKindForModel, k8sDelete } from '@openshift-console/dynamic-plugin-sdk';
12	import { Alert, ButtonVariant, Stack, StackItem } from '@patternfly/react-core';
13	import { getName, getNamespace, getOwnerReference } from '@utils/crds/common/selectors';
14	
15	type PlanDeleteModalProps = {
16	  plan: V1beta1Plan;
17	};
18	
19	const PlanDeleteModal: FC<PlanDeleteModalProps> = ({ plan }) => {
20	  const { t } = useForkliftTranslation();
21	  const navigate = useNavigate();
22	
23	  const name = getName(plan);
24	  const namespace = getNamespace(plan);
25	  const owner = getOwnerReference(plan);
26	
27	  const onDelete = useCallback(async () => {
28	    const deleted = k8sDelete({ model: PlanModel, resource: plan });
29	    navigate(
30	      getResourceUrl({ groupVersionKind: getGroupVersionKindForModel(PlanModel), namespace }),
31	    );
32	
33	    return deleted;
34	  }, [namespace, navigate, plan]);
35	
36	  const status = getPlanStatus(plan);
37	
38	  return (
39	    <ModalForm
40	      confirmVariant={ButtonVariant.danger}
41	      confirmLabel={t('Delete')}
42	      onConfirm={onDelete}
43	      title={t('Delete plan')}
44	    >
45	      <Stack hasGutter>
46	        <StackItem>
47	          <ForkliftTrans>
48	            Are you sure you want to delete <strong className="co-break-word">{name}</strong> in
49	            {namespace && (
50	              <>
51	                {' '}
52	                project <strong>{namespace}</strong>
53	              </>
54	            )}
55	            ?
56	          </ForkliftTrans>
57	        </StackItem>
58	        <StackItem>
59	          {status === PlanStatuses.Executing && (
60	            <Alert
61	              variant="danger"
62	              title={t('Plan is currently running')}
63	              className="forklift-delete-modal__alert"
64	            />
65	          )}
66	        </StackItem>
67	        <StackItem>
68	          {status !== PlanStatuses.Archived && (
69	            <Alert
70	              variant="info"
71	              title={t('Plan is not archived')}
72	              className="forklift-delete-modal__alert"
73	            >
74	              <ForkliftTrans>
75	                Deleting a migration plan does not remove temporary resources, it is recommended to{' '}
76	                <strong>archive</strong> the plan first before deleting it, to remove temporary
77	                resources.
78	              </ForkliftTrans>
79	            </Alert>
80	          )}
81	        </StackItem>
82	        <StackItem>
83	          <ItemIsOwnedAlert owner={owner!} namespace={namespace} />
84	        </StackItem>
85	      </Stack>
86	    </ModalForm>
87	  );
88	};
89	
90	export default PlanDeleteModal;

